 1	import * as React from 'react';
 2	import { ExpandableSection } from '@patternfly/react-core';
 3	
 4	interface ExpandCollapseProps {
 5	  textExpanded: string;
 6	  textCollapsed: string;
 7	  onToggle?: (isExpanded: boolean) => void;
 8	  dataTest?: string;
 9	}
10	
11	export const ExpandCollapse: React.FC<ExpandCollapseProps> = ({
12	  textCollapsed,
13	  textExpanded,
14	  onToggle,
15	  dataTest,
16	  children,
17	}) => {
18	  const [isExpanded, toggleExpandCollapse] = React.useState(false);
19	  return (
20	    <ExpandableSection
21	      toggleTextExpanded={textExpanded}
22	      toggleTextCollapsed={textCollapsed}
23	      onToggle={() => {
24	        onToggle?.(!isExpanded);
25	        toggleExpandCollapse(!isExpanded);
26	      }}
27	      data-test={dataTest}
28	    >
29	      {children}
30	    </ExpandableSection>
31	  );
32	};

